#include<bits/stdc++.h>

#define INPUTFILE "beamdrone.in"
#define OUTPUTFILE "beamdrone.out"

#define NOTFREE 'W'

using namespace std;

// This function checks if a cell is inside the matrix
bool valid(int i, int j, int n, int m) {
    return i >= 0 && j >= 0 && i < n && j < m;
}

int main() {
    freopen(INPUTFILE, "r", stdin);
    freopen(OUTPUTFILE, "w+", stdout);
    // Read the input
    int n, m;
    int x, y;
    cin >> n >> m;

    int source_x, source_y, dest_x, dest_y;
    cin >> source_x >> source_y >> dest_x >> dest_y;

    vector<string> mat(n);
    for (int i = 0; i < n; ++i)
        cin >> mat[i];

    // Distance will store minimum number of turn need
    // to take to reach that cell
    vector<vector<int>> dist(n, vector<int>(m, INT_MAX));
    // Visited will keep track of whether
    // the given cell is visited in bfs or not
    vector<vector<bool>> vis(n, vector<bool>(m, false));
    // To store the order of cells in bfs
    queue<pair<int, int>> q;

    // Initialization
    dist[source_x][source_y] = -1;
    vis[source_x][source_y] = true;

    q.push({source_x, source_y});
    while (!q.empty()) {
        pair<int, int> cell = q.front();
        // If we get the destination cell then
        // we can break as we get the answer
        if (cell.first == dest_x && cell.second == dest_y) {
            break;
        }
        q.pop();

        // -1, 0
        x = cell.first;
        y = cell.second;
        // While the cell is valid, avaliable
        // and the current distance is greater than the initial distance
        while (valid(x - 1, y, n, m) && mat[x - 1][y] != NOTFREE &&
               dist[x - 1][y] >= dist[cell.first][cell.second] + 1) {
            // Update the current distance
            dist[x - 1][y] = dist[cell.first][cell.second] + 1;
            x--;
            // Check if it was visited
            if (!vis[x][y]) {
                vis[x][y] = true;
                q.push({x, y});
            }
        }

        // 1, 0
        x = cell.first;
        y = cell.second;
        // While the cell is valid, avaliable
        // and the current distance is greater than the initial distance
        while (valid(x + 1, y, n, m) && mat[x + 1][y] != NOTFREE &&
               dist[x + 1][y] >= dist[cell.first][cell.second] + 1) {
            // Update the current distance
            dist[x + 1][y] = dist[cell.first][cell.second] + 1;
            x++;
            // Check if it was visited
            if (!vis[x][y]) {
                vis[x][y] = true;
                q.push({x, y});
            }
        }

        // 0, -1
        x = cell.first;
        y = cell.second;
        // While the cell is valid, avaliable
        // and the current distance is greater than the initial distance
        while (valid(x, y - 1, n, m) && mat[x][y - 1] != NOTFREE &&
               dist[x][y - 1] >= dist[cell.first][cell.second] + 1) {
            // Update the current distance
            dist[x][y - 1] = dist[cell.first][cell.second] + 1;
            y--;
            // Check if it was visited
            if (!vis[x][y]) {
                vis[x][y] = true;
                q.push({x, y});
            }
        }

        // 0, 1
        x = cell.first;
        y = cell.second;
        // While the cell is valid, avaliable
        // and the current distance is greater than the initial distance
        while (valid(x, y + 1, n, m) && mat[x][y + 1] != NOTFREE &&
               dist[x][y + 1] >= dist[cell.first][cell.second] + 1) {
            // Update the current distance
            dist[x][y + 1] = dist[cell.first][cell.second] + 1;
            y++;
            // Check if it was visited
            if (!vis[x][y]) {
                vis[x][y] = true;
                q.push({x, y});
            }
        }
    }
    // In case start and destination are same the answer
    // should be 0
    dist[source_x][source_y] = 0;
    cout << dist[dest_x][dest_y] << endl;
}

import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.util.ArrayDeque;

public class Beamdrone {
	static BufferedReader in;
	static BufferedWriter out;

	int N, M;
	int sx, sy;
	int fx, fy;

	char[][] input;
	int[][][] turns;

	ArrayDeque<Node2> deque; 

	int[] dir_x = {-1, 0, 1, 0};
	int[] dir_y = {0, 1, 0, -1};

	public Beamdrone(int N, int M, int sx, int sy, int fx, int fy, char[][] input) {
		this.N = N;
		this.M = M;
		this.sx = sx;
		this.sy = sy;
		this.fx = fx;
		this.fy = fy;
		this.input = input;

		this.turns = new int[4][N][M];

		// Initialize turn matrix to MAX_VALUE
		for (int dir = 0; dir < 4; dir++) {
			for (int x = 0; x < N; x++) {
				for (int y = 0; y < M; y++) {
					this.turns[dir][x][y] = Integer.MAX_VALUE;
				}
			}
		}

		this.deque = new ArrayDeque<>();
	}

	public int getLeastTurns() {
		int result = Integer.MAX_VALUE;

		// Add source node neighbours into the queue
		for (int dir = 0; dir < 4; dir++) {
			Node2 next = new Node2(dir, sx + dir_x[dir], sy + dir_y[dir]);

			// Check if out of bounds
			if (next.x < 0 || next.x >= N || next.y < 0 || next.y >= M) {
				continue;
			}

			if (input[next.x][next.y] == '.') {
				turns[dir][next.x][next.y] = 0;
				deque.addLast(next);
			}

		}

		while (deque.isEmpty() == false) {
			// Get first element of the queue
			Node2 node = deque.removeFirst();

			// Do for every neighbour
			for (int dir = 0; dir < 4; dir++) {
				Node2 next = new Node2(dir, node.x + dir_x[dir], node.y + dir_y[dir]);

				// Check if the current direction is opposite the predecesor
				if (node.dir == 0 && next.dir == 2) {
					continue;
				}
				if (node.dir == 1 && next.dir == 3) {
					continue;
				}
				if (node.dir == 2 && next.dir == 0) {
					continue;
				}
				if (node.dir == 3 && next.dir == 1) {
					continue;
				}

				// Check if out of bounds
				if (next.x < 0 || next.x >= N || next.y < 0 || next.y >= M) {
					continue;
				}

				// If there is a free cell
				if (input[next.x][next.y] == '.') {
					if (next.dir != node.dir) {
						// Not forward
						// Recompute the minimum cost
						if (turns[next.dir][next.x][next.y] > turns[node.dir][node.x][node.y] + 1) {
							turns[next.dir][next.x][next.y] = turns[node.dir][node.x][node.y] + 1;
							deque.addLast(next);
						}
					} else {
						// Forward
						// Recompute the minimum cost
						if (turns[next.dir][next.x][next.y] > turns[node.dir][node.x][node.y]) {
							turns[next.dir][next.x][next.y] = turns[node.dir][node.x][node.y];
							deque.addFirst(next);
						}
					}

					// Compute minimum of turns for the finish point
					if (next.x == fx && next.y == fy) {
						if (turns[next.dir][next.x][next.y] < result) {
							result = turns[next.dir][next.x][next.y];
						}
					}
				}
			}
		}

		return result;
	}

	public static void main(String[] args) throws Exception {
		in = new BufferedReader(new FileReader("beamdrone.in"));
		out = new BufferedWriter(new FileWriter("beamdrone.out"));

		// Perform the reading
		Beamdrone sol = doRead();

		// Get least turns path cost from start to finish
		int result = sol.getLeastTurns();

		// Write the result
		out.write(result + "");

		in.close();
		out.close();
	}

	public static Beamdrone doRead() throws Exception {
		String[] tokens;

		// Read N, M
		tokens = in.readLine().trim().split("\\s+");
		int N, M;
		N = Integer.parseInt(tokens[0]);
		M = Integer.parseInt(tokens[1]);

		// Read initial and final positions
		tokens = in.readLine().trim().split("\\s+");
		int sx = Integer.parseInt(tokens[0]);
		int sy = Integer.parseInt(tokens[1]);
		int fx = Integer.parseInt(tokens[2]);
		int fy = Integer.parseInt(tokens[3]);

		// Read matrix
		char[][] input = new char[N][M];

		for (int i = 0; i < N; i++) {
			String line = in.readLine().trim();
			for (int j = 0; j < M; j++) {
				input[i][j] = line.charAt(j);
			}
		}

		return new Beamdrone(N, M, sx, sy, fx, fy, input);
	}
}

class Node2 {
	public int dir;
	public int x;
	public int y;

	public Node2() {}

	public Node2(int dir, int x, int y) {
		this.dir = dir;
		this.x = x;
		this.y = y;
	}
}
